import{_ as e,o as a,c as l,a as i}from"./app.9ed7caa4.js";const m=JSON.parse('{"title":"Channels","description":"","frontmatter":{"title":"Channels","outline":"deep"},"headers":[{"level":2,"title":"Official Channels","slug":"official-channels","link":"#official-channels","children":[{"level":3,"title":"Main OAC Channel","slug":"main-oac-channel","link":"#main-oac-channel","children":[]},{"level":3,"title":"BGM Channel","slug":"bgm-channel","link":"#bgm-channel","children":[]}]},{"level":2,"title":"Playlists","slug":"playlists","link":"#playlists","children":[{"level":3,"title":"Featured Playlist","slug":"featured-playlist","link":"#featured-playlist","children":[]},{"level":3,"title":"Jazz Ballad Series","slug":"jazz-ballad-series","link":"#jazz-ballad-series","children":[]},{"level":3,"title":"Rock Ballad Series","slug":"rock-ballad-series","link":"#rock-ballad-series","children":[]},{"level":3,"title":"Loop / Visual Series","slug":"loop-visual-series","link":"#loop-visual-series","children":[]}]},{"level":2,"title":"Recommended Usage","slug":"recommended-usage","link":"#recommended-usage","children":[]},{"level":2,"title":"Notes","slug":"notes","link":"#notes","children":[]}],"relativePath":"channels/index.md"}'),n={name:"channels/index.md"},s=i('<h1 id="\u{1F4FA}-channels" tabindex="-1">\u{1F4FA} Channels <a class="header-anchor" href="#\u{1F4FA}-channels" aria-hidden="true">#</a></h1><p>Lyri \xD7 Brian Studio\uC640 \uC5F0\uACB0\uB41C \uACF5\uC2DD \uCC44\uB110 \uBC0F \uD50C\uB808\uC774\uB9AC\uC2A4\uD2B8 \uB9C1\uD06C\uB97C \uBAA8\uC544\uB454 \uD398\uC774\uC9C0\uC785\uB2C8\uB2E4.<br> \uBC29\uBB38\uC790\uAC00 \uC5B4\uB5A4 \uCC44\uB110\uC5D0\uC11C \uBB34\uC5C7\uC744 \uBCFC \uC218 \uC788\uB294\uC9C0 \uBC14\uB85C \uC774\uD574\uD560 \uC218 \uC788\uB3C4\uB85D \uC815\uB9AC\uD569\uB2C8\uB2E4.</p><hr><h2 id="official-channels" tabindex="-1">Official Channels <a class="header-anchor" href="#official-channels" aria-hidden="true">#</a></h2><h3 id="main-oac-channel" tabindex="-1">Main OAC Channel <a class="header-anchor" href="#main-oac-channel" aria-hidden="true">#</a></h3><p>\uC544\uD2F0\uC2A4\uD2B8 \uC544\uCE74\uC774\uBE0C \uC131\uACA9\uC758 \uBA54\uC778 \uCC44\uB110\uC785\uB2C8\uB2E4.<br> \uC568\uBC94, \uD2B8\uB799\uBCC4 \uC601\uC0C1, \uACF5\uC2DD \uC5C5\uB85C\uB4DC\uB97C \uC911\uC2EC\uC73C\uB85C \uC6B4\uC601\uD569\uB2C8\uB2E4.</p><ul><li>Role: Official Artist Archive</li><li>Content: \uC568\uBC94 \uC601\uC0C1 / \uD2B8\uB799 \uC601\uC0C1 / \uACF5\uC2DD \uCF58\uD150\uCE20</li><li>Link: \uCC44\uB110 \uB9C1\uD06C \uCD94\uAC00 \uC608\uC815</li></ul><hr><h3 id="bgm-channel" tabindex="-1">BGM Channel <a class="header-anchor" href="#bgm-channel" aria-hidden="true">#</a></h3><p>\uBD84\uC704\uAE30 \uC911\uC2EC\uC758 \uC7AC\uC988 BGM, \uCE74\uD398 \uC74C\uC545, \uC7A5\uC2DC\uAC04 \uAC10\uC0C1\uC6A9 \uCF58\uD150\uCE20\uB97C \uC6B4\uC601\uD558\uB294 \uCC44\uB110\uC785\uB2C8\uB2E4.</p><ul><li>Role: Background Music Channel</li><li>Content: \uC7AC\uC988 BGM / \uBD84\uC704\uAE30 \uC74C\uC545 / \uB77C\uC774\uBE0C \uBC0F \uC7A5\uC2DC\uAC04 \uC601\uC0C1</li><li>Link: \uCC44\uB110 \uB9C1\uD06C \uCD94\uAC00 \uC608\uC815</li></ul><hr><h2 id="playlists" tabindex="-1">Playlists <a class="header-anchor" href="#playlists" aria-hidden="true">#</a></h2><h3 id="featured-playlist" tabindex="-1">Featured Playlist <a class="header-anchor" href="#featured-playlist" aria-hidden="true">#</a></h3><p>\uB300\uD45C\uACE1\uACFC \uBA54\uC778 \uC791\uD488\uC744 \uBAA8\uC544\uB454 \uD50C\uB808\uC774\uB9AC\uC2A4\uD2B8</p><h3 id="jazz-ballad-series" tabindex="-1">Jazz Ballad Series <a class="header-anchor" href="#jazz-ballad-series" aria-hidden="true">#</a></h3><p>\uC7AC\uC988 \uBC1C\uB77C\uB4DC \uC911\uC2EC\uC758 \uC2DC\uB9AC\uC988 \uD50C\uB808\uC774\uB9AC\uC2A4\uD2B8</p><h3 id="rock-ballad-series" tabindex="-1">Rock Ballad Series <a class="header-anchor" href="#rock-ballad-series" aria-hidden="true">#</a></h3><p>\uB85D \uBC1C\uB77C\uB4DC \uBC0F \uC11C\uC0AC\uD615 \uC568\uBC94 \uD50C\uB808\uC774\uB9AC\uC2A4\uD2B8</p><h3 id="loop-visual-series" tabindex="-1">Loop / Visual Series <a class="header-anchor" href="#loop-visual-series" aria-hidden="true">#</a></h3><p>\uB8E8\uD504 \uC601\uC0C1\uACFC \uAC10\uC131 \uBE44\uC8FC\uC5BC \uC911\uC2EC \uD50C\uB808\uC774\uB9AC\uC2A4\uD2B8</p><hr><h2 id="recommended-usage" tabindex="-1">Recommended Usage <a class="header-anchor" href="#recommended-usage" aria-hidden="true">#</a></h2><p>\uC774 \uD398\uC774\uC9C0\uB294 \uC720\uD29C\uBE0C \uCC44\uB110 \uC18C\uAC1C\uB780\uC5D0 \uC5F0\uACB0\uD558\uB294 \uC678\uBD80 \uD5C8\uBE0C \uC5ED\uD560\uC744 \uD569\uB2C8\uB2E4.<br> \uCC98\uC74C \uBC29\uBB38\uD55C \uC0AC\uB78C\uC774 \uCC44\uB110 \uAD6C\uC870\uB97C \uBE60\uB974\uAC8C \uC774\uD574\uD558\uB3C4\uB85D \uB9CC\uB4DC\uB294 \uAC83\uC774 \uBAA9\uC801\uC785\uB2C8\uB2E4.</p><hr><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-hidden="true">#</a></h2><p>\uCC44\uB110 \uC218\uAC00 \uB298\uC5B4\uB098\uB354\uB77C\uB3C4, \uC774 \uD398\uC774\uC9C0\uB97C \uD1B5\uD574 \uBA54\uC778 \uCC44\uB110\uACFC \uC11C\uBE0C \uCC44\uB110\uC758 \uC5ED\uD560\uC744 \uBD84\uB9AC\uD574\uC11C \uBCF4\uC5EC\uC904 \uC218 \uC788\uC2B5\uB2C8\uB2E4.</p>',27),r=[s];function d(h,t,c,o,u,p){return a(),l("div",null,r)}const _=e(n,[["render",d]]);export{m as __pageData,_ as default};
